373→  if (value === null) {
374→    return "null";
375→  }
376→
377→  if (typeof value === "string") {
378→    return truncateString(value, 4000);
379→  }
380→
381→  if (typeof value === "number" || typeof value === "boolean" || value === undefined) {
382→    return value;
383→  }
384→
385→  if (value instanceof Date) {
386→    return value.toISOString();
387→  }
388→
389→  if (Array.isArray(value)) {
390→    return value.slice(0, 20).map((item) => serializeUnknown(item, depth + 1, seen));
391→  }
392→
393→  if (value instanceof Error) {
394→    return serializeError(value, depth + 1);
395→  }
396→
397→  if (!isRecord(value)) {
398→    return String(value);
399→  }
400→
401→  if (seen.has(value)) {
402→    return "[circular]";
403→  }
404→  seen.add(value);
405→
406→  const output: Record<string, unknown> = {};
407→  for (const [key, entryValue] of Object.entries(value).slice(0, 30)) {
408→    const normalizedKey = key.toLowerCase();
409→    if (normalizedKey === "user_id" || normalizedKey === "userid" || normalizedKey === "api_key" || normalizedKey === "apikey") {
410→      output[key] = "[redacted]";
411→      continue;
412→    }
413→    output[key] = serializeUnknown(entryValue, depth + 1, seen);
414→  }
415→  return output;
416→}
417→
418→function isRecord(value: unknown): value is Record<string, unknown> {
419→  return typeof value === "object" && value !== null;
420→}
421→
422→function truncateString(value: string, maxLength: number): string {
423→  if (value.length <= maxLength) {
424→    return value;
425→  }
426→  return `${value.slice(0, maxLength)}…[truncated]`;
