 15→import type { GraphEntityRecord, SourceRecord } from "../extraction/types";
 16→import { HttpError } from "../http/errors";
 17→import { elapsedMs, logDebug, logError, logInfo, logWarn } from "../http/observability";
 18→import { parseCreateWorkspaceRequest } from "../http/parsing";
 19→import { jsonError, jsonResponse, toIsoString } from "../http/response";
 20→import type { ServerDependencies } from "../runtime/types";
 21→import { toOnboardingState } from "../onboarding/onboarding-state";
 22→import { resolveWorkspaceRecord } from "./workspace-scope";
 23→import { buildWorkspaceConversationSidebar } from "./conversation-sidebar";
 24→import { loadMessagesWithInheritance } from "../chat/branch-chain";
 25→import { validateRepoPath } from "./validate-repo-path";
 26→import { bootstrapWorkspaceIdentities } from "./identity-bootstrap";
 27→import type { ShellExecResult } from "../orchestrator/worktree-manager";
 28→
 29→type WorkspaceRow = {
 30→  id: RecordId<"workspace", string>;
 31→  name: string;
 32→  description?: string;
 33→  repo_path?: string;
 34→  status: string;
 35→  onboarding_complete: boolean;
 36→  onboarding_turn_count: number;
 37→  onboarding_summary_pending: boolean;
 38→};
 39→
 40→type ProvenanceEdgeRow = {
 41→  id: RecordId<"extraction_relation", string>;
 42→  in: SourceRecord;
 43→  out: GraphEntityRecord;
 44→  confidence: number;
 45→  extracted_at: Date | string;
 46→};
 47→
 48→type ShellExec = (command: string, args: string[], cwd: string) => Promise<ShellExecResult>;
 49→
 50→export function createWorkspaceRouteHandlers(
 51→  deps: ServerDependencies,
 52→  shellExec?: ShellExec,
 53→): {
 54→  handleCreateWorkspace: (request: Request) => Promise<Response>;
 55→  handleWorkspaceBootstrap: (workspaceId: string) => Promise<Response>;
 56→  handleWorkspaceSidebar: (workspaceId: string) => Promise<Response>;
 57→  handleWorkspaceConversation: (workspaceId: string, conversationId: string) => Promise<Response>;
 58→  handleUpdateRepoPath: (workspaceId: string, request: Request) => Promise<Response>;
 59→} {
 60→  return {
 61→    handleCreateWorkspace: (request: Request) => handleCreateWorkspace(deps, request, shellExec),
 62→    handleWorkspaceBootstrap: (workspaceId: string) => handleWorkspaceBootstrap(deps, workspaceId),
 63→    handleWorkspaceSidebar: (workspaceId: string) => handleWorkspaceSidebar(deps, workspaceId),
 64→    handleWorkspaceConversation: (workspaceId: string, conversationId: string) =>
 65→      handleWorkspaceConversation(deps, workspaceId, conversationId),
 66→    handleUpdateRepoPath: (workspaceId: string, request: Request) =>
 67→      handleUpdateRepoPath(deps, workspaceId, request, shellExec),
 68→  };
 69→}
 70→
 71→async function handleCreateWorkspace(deps: ServerDependencies, request: Request, shellExec?: ShellExec): Promise<Response> {
 72→  const startedAt = performance.now();
 73→  logInfo("workspace.create.started", "Workspace creation started");
 74→
 75→  const session = await deps.auth.api.getSession({ headers: request.headers });
 76→  if (!session?.user?.id) {
 77→    return jsonError("authentication required", 401);
 78→  }
 79→
 80→  let body: unknown;
 81→  try {
 82→    body = await request.json();
 83→  } catch {
 84→    return jsonError("Request body must be valid JSON", 400);
 85→  }
 86→
 87→  const parsed = parseCreateWorkspaceRequest(body);
 88→  if (!parsed.ok) {
 89→    return jsonError(parsed.error, 400);
 90→  }
 91→
 92→  // Validate repoPath if provided
 93→  if (parsed.data.repoPath && shellExec) {
 94→    const repoValidation = await validateRepoPath(parsed.data.repoPath, shellExec);
 95→    if (!repoValidation.ok) {
 96→      return jsonError(repoValidation.error, 400);
 97→    }
 98→  }
 99→
100→  logDebug("http.request.validated", "Workspace request validated");

